## 2. Minimal C++ “stub” that mimics libpcapng

> **NOTE** – Replace the contents of `libpcapng_stub.hpp` with the real
> headers from `libpcapng`.  The stub only exists so the example can be built
> without pulling in the actual library.

```cpp
// --------------------------------------------------------------
// file: libpcapng_stub.hpp
// --------------------------------------------------------------
#pragma once
#include <cstdint>
#include <vector>
#include <string>
#include <stdexcept>
#include <fstream>
#include <iterator>

/* ------------------------------------------------------------------
 *  A *very* tiny subset of what a real libpcapng library would expose.
 *
 *  - Frame: a POD that holds a timestamp (seconds + nanoseconds) and the
 *           raw packet bytes.
 *  - PcapngFile: a container that can be iterated with a C++ input iterator.
 * ------------------------------------------------------------------ */
namespace libpcapng {

struct Frame {
    uint64_t ts_sec;   // seconds since epoch
    uint32_t ts_nsec;  // nanoseconds portion
    std::vector<uint8_t> data;   // raw packet bytes

    double timestamp() const noexcept {
        return static_cast<double>(ts_sec) + static_cast<double>(ts_nsec) * 1e-9;
    }
};

class PcapngFile {
public:
    explicit PcapngFile(const std::string& path) : ifs_(path, std::ios::binary) {
        if (!ifs_) throw std::runtime_error("cannot open file: " + path);
    }

    /* --------------------------------------------------------------
     *  Very naive frame generator – reads a dummy format:
     *
     *  [8 bytes]   ts_sec   (uint64_t, LE)
     *  [4 bytes]   ts_nsec  (uint32_t, LE)
     *  [4 bytes]   len      (uint32_t, LE)
     *  [len bytes] data
     *
     *  The real library would decode the actual pcapng block structure.
     * -------------------------------------------------------------- */
    class iterator {
        using istream = std::ifstream;
        istream* src_;
        Frame cur_;
        bool   at_end_ = false;

        void read_one() {
            if (!src_ || src_->eof()) { at_end_ = true; return; }

            uint64_t sec = 0; uint32_t nsec = 0, len = 0;
            src_->read(reinterpret_cast<char*>(&sec), 8);
            src_->read(reinterpret_cast<char*>(&nsec), 4);
            src_->read(reinterpret_cast<char*>(&len), 4);
            if (src_->gcount() != 4) { at_end_ = true; return; }

            cur_.ts_sec = sec;
            cur_.ts_nsec = nsec;
            cur_.data.resize(len);
            src_->read(reinterpret_cast<char*>(cur_.data.data()), len);
            if (src_->gcount() != static_cast<std::streamsize>(len))
                at_end_ = true;
        }

    public:
        using iterator_category = std::input_iterator_tag;
        using value_type        = Frame;
        using difference_type   = std::ptrdiff_t;
        using pointer           = const Frame*;
        using reference         = const Frame&;

        explicit iterator(istream* src = nullptr) : src_(src) {
            if (src_) read_one();
        }

        reference operator*() const noexcept { return cur_; }
        pointer   operator->() const noexcept { return &cur_; }

        iterator& operator++() {
            read_one();
            return *this;
        }
        iterator operator++(int) {
            iterator tmp = *this; ++*this; return tmp;
        }

        friend bool operator==(const iterator& a, const iterator& b) noexcept {
            return a.at_end_ == b.at_end_;
        }
        friend bool operator!=(const iterator& a, const iterator& b) noexcept {
            return !(a == b);
        }
    };

    iterator begin() { return iterator(&ifs_); }
    iterator end()   { return iterator(); }

private:
    std::ifstream ifs_;
};

} // namespace libpcapng
```

