## 4. Build system – one‑file CMakeLists.txt

```cmake
# --------------------------------------------------------------
# file: CMakeLists.txt
# --------------------------------------------------------------
cmake_minimum_required(VERSION 3.14...3.30)
project(pcapng_bindings LANGUAGES CXX)

# --------------------------------------------------------------
# 1️⃣  Find pybind11 (it can be installed via pip or as a submodule)
# --------------------------------------------------------------
# Option A: system installation (pip install pybind11)
find_package(pybind11 CONFIG REQUIRED)

# --------------------------------------------------------------
# 2️⃣  Define the extension module
# --------------------------------------------------------------
pybind11_add_module(pcapng
    pcapng_bindings.cpp
)

# --------------------------------------------------------------
# 3️⃣  Add the stub header as a source (no compilation needed)
# --------------------------------------------------------------
target_include_directories(pcapng PRIVATE ${CMAKE_CURRENT_SOURCE_DIR})

# --------------------------------------------------------------
# 4️⃣  Set C++ standard and warning level (optional but nice)
# --------------------------------------------------------------
target_compile_features(pcapng PRIVATE cxx_std_17)
if (MSVC)
    target_compile_options(pcapng PRIVATE /W4 /permissive-)
else()
    target_compile_options(pcapng PRIVATE -Wall -Wextra -Wpedantic)
endif()
```

### Build instructions

```bash
# 1️⃣  Create a build directory
mkdir build && cd build

# 2️⃣  Configure (assumes you have a recent CMake and a Python with pybind11)
cmake .. -DPYTHON_EXECUTABLE=$(which python3)

# 3️⃣  Build
cmake --build . -j$(nproc)

# 4️⃣  The generated `.so` (or `.pyd` on Windows) lives in the build dir.
#     You can now import it from Python:
python3 -c "import pcapng, sys; print('module loaded, version', pcapng.__doc__)"
```

If you prefer not to install `pybind11` system‑wide, you can add it as a submodule:

```bash
git clone --recurse-submodules https://github.com/pybind/pybind11.git
```

and replace the `find_package(pybind11 CONFIG REQUIRED)` line with:

```cmake
add_subdirectory(pybind11)
```

